sys_security_acl.script:
answer = (function canViewConfiguredAction(grCurrentAction) {

	var i, currentRole, strRolesList, arrRequiresRole;

	strRolesList = grCurrentAction.getValue('requires_role');
	//Return true if the "Requires role" field is empty
	if (grCurrentAction.requires_role.nil() || !strRolesList) {
		return gs.isLoggedIn();
	}

	//True if user has any of the roles in the "Requires role" field
	arrRequiresRole = strRolesList.split(',');
	for (i = 0; i < arrRequiresRole.length; i++) {
		currentRole = arrRequiresRole[i].trim();
		if (currentRole && gs.hasRole(currentRole)) {
			return true;
		}
	}

	//Default false
	return false;

})(current);
